const inspector=document.querySelector('#inspector');const editButton=document.querySelector('#editMode');const finishButton=document.querySelector('#finishEdit');const editStatus=document.querySelector('#editStatus');const composer=document.querySelector('#composer');const composerBox=document.querySelector('.composer');const response=document.querySelector('#response');
function setEditing(active){inspector.classList.toggle('editing',active);editStatus.classList.toggle('hidden',!active);composerBox.classList.toggle('editing',active);composer.placeholder=active?'说出要修改的参数、价格或规则…':'描述你的DMPK报价需求…';if(active)composer.focus()}
editButton.addEventListener('click',()=>setEditing(true));finishButton.addEventListener('click',()=>setEditing(false));
document.querySelectorAll('[data-text]').forEach(button=>button.addEventListener('click',()=>{setEditing(true);composer.value=button.dataset.text;composer.focus()}));
document.querySelector('#send').addEventListener('click',()=>{const text=composer.value.trim();if(!text)return;response.classList.remove('hidden');if(text.includes('以后')||text.includes('所有')){response.innerHTML='<header><strong>检测到全局规则需求</strong><span>PK报价</span></header><p>样品不足40个时，按照40个计费。</p><dl><div><dt>影响范围</dt><dd>后续新建的PK报价</dd></div><div><dt>当前任务</dt><dd>不会自动修改</dd></div></dl><footer><button>暂存建议</button><button class="primary">进入PK配置</button></footer>'}else if(text.includes('报告费')||text.includes('报价')){response.innerHTML='<header><strong>本次报价调整</strong><span>仅当前报价</span></header><dl><div><dt>报告费</dt><dd>¥3,000 → ¥2,500</dd></div><div><dt>报价总额</dt><dd>¥52,200 → ¥51,700</dd></div></dl><footer><button>取消</button><button class="primary">确认调整</button></footer>'}else{document.querySelector('#species').textContent='Beagle犬';document.querySelector('#animals').textContent='3';document.querySelector('#groups').textContent='2';document.querySelector('#duration').textContent='14天';document.querySelectorAll('#species,#animals,#groups,#duration').forEach(node=>node.parentElement.classList.add('changed'));response.innerHTML='<header><strong>已更新当前项目参数</strong><span>4项</span></header><dl><div><dt>动物种属</dt><dd>SD大鼠 → Beagle犬</dd></div><div><dt>每组动物数</dt><dd>2 → 3</dd></div><div><dt>组数</dt><dd>2</dd></div><div><dt>实验周期</dt><dd>7天 → 14天</dd></div></dl>'}composer.value=''});
